export type WishlistVisibility = 'link_only' | 'public_profile' | 'private';
export type AllowSubscriptions = 'all' | 'nobody';
export type CommentPolicy = 'all' | 'subscribers';

export type DontGiftMode = 'global' | 'local' | 'hidden';

export type Wishlist = {
  id: string;
  slug: string;
  title: string;
  /** Optional user-chosen emoji shown next to the title. When null, the UI
   *  falls back to a hash-derived auto-pick from `title` via `getEmoji()`. */
  emoji?: string | null;
  description: string | null;
  deadline: string | null;
  itemCount: number;
  reservedCount: number;
  readOnly?: boolean;
  visibility: WishlistVisibility;
  allowSubscriptions: AllowSubscriptions;
  commentPolicy: CommentPolicy;
  shareToken?: string | null;
  dontGiftMode?: DontGiftMode;
  smartReservationsEnabled?: boolean;
  smartResTtlHours?: number;
  smartResAllowExtend?: boolean;
  smartResMaxExtensions?: number;
};

// getWritableTargets extracted to ./lib/wishlist-utils (F5).

export type PlanInfo = {
  code: 'FREE' | 'PRO';
  wishlists: number;
  items: number;
  subscriptions: number;
  participants: number;
  features: string[];
};

// FREE_CATEGORY_LIMIT / PRO_CATEGORY_LIMIT / categoryLimitFor extracted to
// ./lib/wishlist-utils (F5).

export type BillingPeriod = 'monthly' | 'yearly' | 'lifetime';
export type SubscriptionInfo = {
  id: string;
  status: 'ACTIVE' | 'CANCELLED' | 'EXPIRED';
  periodEnd: string;
  cancelledAt: string | null;
  cancelAtPeriodEnd: boolean;
  // billingPeriod surfaces the canonical 'monthly' | 'yearly' | 'lifetime'
  // discriminator from the API. Settings UI and paywall use this — never
  // compare against periodEnd to detect lifetime. Discriminated union so a
  // typo (e.g. 'liftime') is caught at type-check.
  billingPeriod?: BillingPeriod | null;
} | null;

