// ─── Design System: ProBadge ──────────────────────────
// Small filled-gradient "PRO" pill used to mark paid features.
// Fixed dimensions (height 20, padding 0 8) guarantee identical
// rendering across all parent contexts (flex rows, inline text,
// buttons, list items). DO NOT override height/padding via `style`.
// Use ProBadge wherever you need to tag something as PRO.
// ProBadge extracted to ./components/ProBadge — see Phase 5b extraction pilot.

/**
 * Small tile that appears on the profile screen advertising the referral
 * program. Reads from preloaded rules-config (loaded once at app init).
 * Hides itself when the program isn't active for this user (out of rollout /
 * disabled) or when `ui.entryPointProfile` is false in admin config.
 * Impression fires once per profile-screen mount for funnel data.
 */
export type ReferralProfileTileFromConfigProps = {
  /** Server config. `null` while loading or when the program is OFF. */
  config: ReferralRulesConfig | null;
  locale: Locale;
  onOpen: () => void;
  trackEvent: (event: string, props?: Record<string, unknown>) => void;
};
function ReferralProfileTileFromConfig({ config, locale, onOpen, trackEvent }: ReferralProfileTileFromConfigProps) {
  const impressionFiredRef = useRef(false);
  const shouldRender = !!config && config.enabled && config.inRollout && config.ui.entryPointProfile;
  useEffect(() => {
    if (shouldRender && !impressionFiredRef.current) {
      impressionFiredRef.current = true;
      trackEvent('referral.entry_point_impression', { entryPoint: 'profile_tile' });
    }
  }, [shouldRender, trackEvent]);
  if (!shouldRender || !config) return null;
  const days = config.reward.daysPerRef;
  return (
    <div style={{ marginBottom: 12 }}>
      <div
        onClick={onOpen}
        style={{
          position: 'relative', cursor: 'pointer',
          borderRadius: 18,
          background: `linear-gradient(135deg, rgb(var(--wb-accent-r, 139) var(--wb-accent-g, 123) var(--wb-accent-b, 255) / 0.133), rgb(var(--wb-accent-r, 139) var(--wb-accent-g, 123) var(--wb-accent-b, 255) / 0.031))`,
          border: `1px solid rgb(var(--wb-accent-r, 139) var(--wb-accent-g, 123) var(--wb-accent-b, 255) / 0.251)`,
          padding: 16, overflow: 'hidden',
        }}>
        <div style={{ position: 'relative', display: 'flex', alignItems: 'flex-start', gap: 12 }}>
          <div style={{
            width: 44, height: 44, borderRadius: 12,
            background: `linear-gradient(135deg, ${C.accent}, var(--wb-accent-deep, #5B4BD6))`,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 22, flexShrink: 0,
          }}>🎁</div>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ fontSize: 15, fontWeight: 700, color: C.text, marginBottom: 4 }}>
              {t('referral_profile_tile_title', locale)}
            </div>
            <div style={{ fontSize: 13, color: C.textMuted, lineHeight: 1.4 }}>
              {t('referral_profile_tile_desc', locale, { days: String(days) })}
            </div>
          </div>
          <div style={{
            color: C.accent, fontSize: 13, fontWeight: 600,
            padding: '6px 10px', borderRadius: 10, flexShrink: 0,
            background: 'rgb(var(--wb-accent-r, 139) var(--wb-accent-g, 123) var(--wb-accent-b, 255) / 0.12)',
          }}>
            {t('referral_profile_tile_cta', locale)}
          </div>
        </div>
      </div>
    </div>
  );
}

