            background: 'radial-gradient(ellipse at 50% 40%, rgb(var(--wb-accent-r, 139) var(--wb-accent-g, 123) var(--wb-accent-b, 255) / 0.08) 0%, transparent 70%)',
            position: 'relative', overflow: 'hidden',
